		Prompt:   prompt,
		MaxTokens: 40,
		N:        1,
		Stop:     []string{"\""},
	}

	ctx := context.Background()
	resp, err := client.Completion(ctx, conf)
	if err != nil {
		log.Fatalln("Failed to get completion from GPT-3:", err)
	}

