class GCounter {
  private counters: Map<string, Counter>;

  constructor(replicaId: string) {
    this.counters = new Map<string, Counter>();
    this.counters.set(replicaId, { replicaId, count: 0 });
  }

  // Increment the counter for the current replica
  increment(replicaId: string, value: number = 1): void {
    const counter = this.counters.get(replicaId);
    if (counter) {
      this.counters.set(replicaId, { replicaId, count: counter.count + value });
    }
  }

  // Merge the states of two replicas
  merge(otherCounter: GCounter): void {
    for (let [replicaId, other_counter] of otherCounter.counters.entries()) {
      const local_counter = this.counters.get(replicaId);

      if (!local_counter || other_counter.count > local_counter.count) {
        this.counters.set(replicaId, other_counter);
      }
    }
  }

  // Get the total value of the counter
  getValue(): number {
    let total = 0;
    for (let counter of this.counters.values()) {
      total += counter.count;
    }
    return total;
  }
}

// Usage example
