const gCounter2 = new GCounter('replica2');

gCounter1.increment('replica1', 5);
gCounter2.increment('replica2', 3);

gCounter1.merge(gCounter2);

console.log('Counter 1 value:', gCounter1.getValue()); // Output: Counter 1 value: 8
console.log('Counter 2 value:', gCounter2.getValue()); // Output: Counter 2 value: 3
```

