1. Gather the source files you'd like to analyze.

2. Traverse the file system and identify valid Python files (`.py` extension).

3. Use the `ast` library to parse the source code and extract imports.

4. Count the imports, store the results in a dictionary, and normalize the counts.

5. Visualize the import counts using a heat map library like Seaborn.

Here's sample code to demonstrate this process:

```python
import ast
import glob
import os

import seaborn as sns
import matplotlib.pyplot as plt


def count_imports(file_path):
    with open(file_path, 'r', encoding='utf8') as source:
        try:
            tree = ast.parse(source.read())
        except SyntaxError:
            return {}

    imports = {}
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            for alias in node.names:
                module_name = alias.name.split('.')[0]
                imports[module_name] = imports.get(module_name, 0) + 1
    return imports


def gather_import_counts(path):
    all_imports = {}
    py_files = glob.glob(f"{path}/**/*.py", recursive=True)

    for file_path in py_files:
        imports = count_imports(file_path)
        for module, count in imports.items():
            all_imports[module] = all_imports.get(module, 0) + count
    return all_imports


def normalize_import_counts(import_counts):
    total = sum(import_counts.values())
    return {module: count / total for module, count in import_counts.items()}


def plot_heat_map(import_counts):
    # Preprocess data for heatmap
    data = []
    for module, count in import_counts.items():
        data.append([module, count])

