```python
import re

def read_file(file_path):
    with open(file_path, "r", encoding='utf-8') as file:
        text = file.read()
    return text

def remove_punctuation_and_lower(text):
    return re.sub(r'[^\w\s]', '', text).lower()

def count_word_frequency(text):
    word_freq = {}
    words = text.split()

    for word in words:
        if word not in word_freq:
            word_freq[word] = 1
        else:
            word_freq[word] += 1

    return word_freq

def print_word_frequencies(word_freq):
    for word, count in word_freq.items():
        print(f"{word}: {count}")

def main():
    file_path = "example.txt"
    text = read_file(file_path)
    clean_text = remove_punctuation_and_lower(text)
    word_freq = count_word_frequency(clean_text)

    print("Word frequencies:")
    print_word_frequencies(word_freq)

if __name__ == "__main__":
    main()
```

Make sure to replace `"example.txt"` with the path to your text document. When you run this script, it will display the word frequencies in the provided text document.

